SET CLIENT_ENCODING TO UTF8;
SET STANDARD_CONFORMING_STRINGS TO ON;
BEGIN;
CREATE TABLE "veredas" (gid serial,
"objectid" float8,
"codigo" varchar(17),
"codigo_sec" varchar(9),
"nombre" varchar(100),
"codigo_ant" varchar(17),
"globalid" varchar(38),
"created_us" varchar(254),
"created_da" date,
"last_edite" varchar(254),
"last_edi_1" date,
"shape_leng" numeric,
"shape_area" numeric);
ALTER TABLE "veredas" ADD PRIMARY KEY (gid);
SELECT AddGeometryColumn('','veredas','geom','4326','MULTIPOLYGON',2);
CREATE INDEX ON "veredas" USING GIST ("geom");
COMMIT;
ANALYZE "veredas";
